// Simulate k tapes on single tape
// Encoding: #marker1#tape1#marker2#tape2#...#markerk#tapek#

FUNCTION Simulate_MultiTape(TM_k_tape, input):
 // Convert input to single tape format
 single_tape ← encode_multiple_tapes(input, k)
 state ← (q0, 0, 0, ..., 0) // TM state + head positions

 // Each transition of k-tape TM becomes multiple passes
 REPEAT:
 // PASS 1: Find all markers and record symbols
 Move right, record symbols at each track position

 // PASS 2: Based on recorded symbols and TM transition table,
 // determine what to write and new head directions

 // PASS 3: Make the writes and move heads
 Move to each marker position and update symbols/directions

 // Update control state
 state ← next_state_of_TM
 UNTIL state is halting state

 // Extract output from first tape encoding
 RETURN decode_output(single_tape)

// NDTM accepts if ANY branch leads to accept
// DTM simulation using systematic exploration

FUNCTION Simulate_NDTM(ndtm, input):
 // Configuration tree: each node = TM configuration
 // Root = initial configuration
 queue ← [initial_configuration(input)]

 WHILE queue is not empty:
 config ← dequeue(queue) // BFS order

 IF config.state ∈ F THEN
 RETURN ACCEPT // Found accepting path
 END IF

 // Get all possible transitions from current config
 next_configs ← get_all_transitions(config)

 // Enqueue all possible next configurations
 FOR each cfg IN next_configs:
 enqueue(queue, cfg)
 END FOR

 // Check for empty queue (no more configs to explore)
 IF queue is empty THEN
 RETURN REJECT // No accepting path exists
 END IF
 END WHILE

 // For some inputs, NDTM may never halt
 // DTM may loop exploring infinite branches
 RETURN LOOP (indeterminate)

// Universal Turing Machine U
// Input: <M>#w where M = encoding of TM, w = input string

FUNCTION Universal_TM(encoded_TM, input_w):
 // Step 1: Parse and store the description of TM M
 // M = (Q, Σ, Γ, δ, q0, B, F) encoded as string
 TM_description ← parse_TM_encoding(encoded_TM)

 // Step 2: Initialize work tape with input w
 work_tape ← initialize_with(input_w)
 current_state ← TM_description.q0

 // Step 3: Main simulation loop
 WHILE current_state ∉ TM_description.F:
 // Read current symbol under head on work tape
 current_symbol ← work_tape[head_position]

 // Look up transition in M's δ table
 // δ(current_state, current_symbol) → (next_state, write, move)
 transition ← TM_description.δ(current_state, current_symbol)

 IF transition does not exist THEN
 RETURN REJECT // No valid move - halt without accepting
 END IF

 // Execute the transition on work tape
 work_tape[head_position] ← transition.write_symbol
 head_position ← head_position + transition.move_direction
 current_state ← transition.next_state
 END WHILE

 // If we reached a final state, M accepts w
 RETURN ACCEPT
